# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).
# Category: path_traversal

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    public class FileController : Controller
    {
        private const string RootFolder = "uploads";

        [HttpGet("{file}")]
        public ActionResult Download(string file)
        {
            var path = Path.Combine(RootFolder, file);

            if (!System.IO.File.Exists(path))
            {
                return NotFound();
            }

            var contentType = MimeMapping.GetMimeMapping(path);
            var fileBytes = System.IO.File.ReadAllBytes(path);

            return File(fileBytes, contentType, System.IO.Path.GetFileName(path));
        }
    }
}